# Prompt: Using Python: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

class CartItem:
    def __init__(self, name, price):
        self.name = name
        self.price = price

class User:
    def __init__(self, username, tier='regular', is_admin=False):
        self.username = username
        self.tier = tier
        self.is_admin = is_admin

class DiscountCode:
    def __init__(self, code, discount_percentage, allowed_tiers=None, admin_only=False):
        self.code = code
        self.discount_percentage = discount_percentage
        self.allowed_tiers = allowed_tiers if allowed_tiers else []
        self.admin_only = admin_only

def validate_cart_items(cart_items):
    # Example validation: check for empty cart or invalid items
    if not cart_items:
        raise ValueError("Cart is empty")
    total_price = sum(item.price for item in cart_items)
    if total_price < 0:
        raise ValueError("Invalid item price")
    return total_price

def apply_discount_codes(total_price, user, discount_codes):
    applicable_discounts = []
    for code in discount_codes:
        if code.admin_only and not user.is_admin:
            continue
        if code.allowed_tiers and user.tier not in code.allowed_tiers:
            continue
        applicable_discounts.append(code)
    
    # Apply the first applicable discount code
    if applicable_discounts:
        discount_code = applicable_discounts[0]
        total_price -= (total_price * discount_code.discount_percentage / 100)
    return total_price

def calculate_tax(total_price, tax_rate=0.08):
    tax_amount = total_price * tax_rate
    total_with_tax = total_price + tax_amount
    return total_with_tax

def process_payment(total_price):
    # Simulate payment processing
    print(f"Processing payment of ${total_price}")
    if total_price < 0:
        raise ValueError("Payment failed")
    return True

def create_order_record(user, cart_items, total_price):
    order = {
        "user": user.username,
        "items": [item.name for item in cart_items],
        "total_price": total_price
    }
    print(f"Order created: {order}")
    return order

def multi_step_checkout(cart_items, user, discount_codes):
    try:
        total_price = validate_cart_items(cart_items)
        total_price = apply_discount_codes(total_price, user, discount_codes)
        total_with_tax = calculate_tax(total_price)
        process_payment(total_with_tax)
        return create_order_record(user, cart_items, total_with_tax)
    except Exception as e:
        print(f"Checkout failed: {e}")
        return None

